select t.eid, t.qtid, t.sid, t.qtorder, t.isfinish, t.qttime
  from student_answer_qtype_exam t
 where t.eid = #{eid,jdbcType=NVARCHAR}
   and t.sid = #{sid,jdbcType=NVARCHAR}
   and t.isfinish = 0
 order by t.qtorder

