update student_answer_qtype_exam t
set t.isfinish = 1
where t.eid = #{eid,jdbcType=NVARCHAR} and t.sid = #{sid,jdbcType=NVARCHAR} and t.qtid = #{qtid,jdbcType=NVARCHAR}

update student_exam_exam


		usetime = #{usetime},


where eid = #{eid,jdbcType=NVARCHAR} and sid = #{sid,jdbcType=NVARCHAR}

update student_answer_qtype_exam saqt set saqt.qttime = (saqt.qttime - #{answertime})
	where saqt.eid = #{eid,jdbcType=VARCHAR}
		and saqt.qtid = #{qtid,jdbcType=VARCHAR}
		and saqt.sid = #{sid,jdbcType=VARCHAR}

update department 
set name = #{dname}, 
	unitid = #{uid}, 
	uname = #{uname}
where id = #{did,jdbcType=VARCHAR}

update department_synchronization
set id = #{did}
where unitname = #{uname,jdbcType=VARCHAR}
and departmentname = #{dname,jdbcType=VARCHAR}

