and qtid=#{qtid,jdbcType=VARCHAR}

mapper.select:
select se.state as state,
	se.princ_state as princ_state
 from student_exam_exam se where se.sid = #{sid,jdbcType=VARCHAR} and se.eid = #{eid,jdbcType=VARCHAR}

select epq.qid as qid, epq.iscon as qtiscon, epq.mqid as mqid, epq.ismain as ismain, epq.cid as cid, epq.answertime_bachelor as time, epq.score as score, epq.qtid as qtype, epq.atid as atid, epq.answerid as answerid, epq.content as content, epq.filepath as filepath, epq.th as th, a.aid as aid, a.content_6 as acontent1, a.content as acontent2 from exampaper_question_db epq left join exampaper_answer a on epq.qid = a.qid and epq.eid = a.eid where epq.qid in
#{item,jdbcType=VARCHAR}
and epq.eid = #{eid,jdbcType=VARCHAR} order by epq.th,a.aid

select t.eid, t.qtid, t.sid, t.qtorder, t.isfinish, eqt.qtname as qtname, nvl(eqt.e_qtname,'') as e_qtname, eqt.qtdesc as qdesc, nvl(eqt.e_qtdesc,'') as e_qtdesc, eqt.iscon as iscon, eqt.sxb as sxb, eqt.xxdf as xxdf from student_answer_qtype_exam t left join exampaper_questiontype eqt on eqt.qtid=t.qtid and eqt.eid=t.eid where t.eid = #{eid,jdbcType=VARCHAR} and t.sid = #{sid,jdbcType=VARCHAR} and t.qtid in
#{item,jdbcType=VARCHAR}
order by t.qtorder
